import threading

class Account:
    def __init__(self, balance=0):
        self.balance = balance
        self.lock = threading.Lock()

    def update_balance(self, amount):
        with self.lock:
            self.balance += amount
            return self.balance

class TransactionProcessor:
    def __init__(self):
        self.accounts = {}

    def create_account(self, account_id, initial_balance=0):
        if account_id not in self.accounts:
            self.accounts[account_id] = Account(initial_balance)

    def process_transaction(self, account_id, amount):
        if account_id not in self.accounts:
            raise ValueError("Account does not exist")

        account = self.accounts[account_id]
        with account.lock:
            # Validate transaction
            if amount < 0 and account.balance + amount < 0:
                raise ValueError("Insufficient funds")

            # Update balance atomically
            new_balance = account.update_balance(amount)
            return new_balance

